export function decodeManagedRuntimeChangePage(value: unknown): ManagedRuntimeChangePage {
  const page = record(value, "$");
  const gap =
    page.gap === null
      ? null
      : (() => {
          const source = record(page.gap, "$.gap");
          return {
            ...source,
            requested_after: optionalRuntimeU64(source.requested_after, "$.gap.requested_after"),
            earliest_available: runtimeU64(source.earliest_available, "$.gap.earliest_available"),
            latest_available: runtimeU64(source.latest_available, "$.gap.latest_available"),
            snapshot_revision: runtimeU64(source.snapshot_revision, "$.gap.snapshot_revision"),
          };
        })();
  return {
    ...(page as unknown as ManagedRuntimeChangePageWire),
    changes: array(page.changes, "$.changes").map((change, index) =>
      decodeManagedRuntimePlatformChange(change, `$.changes[${index}]`)
    ),
    next: runtimeU64(page.next, "$.next"),
    gap,
  } as ManagedRuntimeChangePage;
}

export function encodeManagedRuntimeChangePage(
  page: ManagedRuntimeChangePage,
): ManagedRuntimeChangePageWire {
  return {
    ...page,
    changes: page.changes.map(encodeManagedRuntimePlatformChange),
    next: encodeRuntimeU64(page.next),
    gap:
      page.gap === null
        ? null
        : {
            ...page.gap,
            requested_after:
              page.gap.requested_after === null
                ? null
                : encodeRuntimeU64(page.gap.requested_after),
            earliest_available: encodeRuntimeU64(page.gap.earliest_available),
            latest_available: encodeRuntimeU64(page.gap.latest_available),
            snapshot_revision: encodeRuntimeU64(page.gap.snapshot_revision),
          },
  } as ManagedRuntimeChangePageWire;
}

export function decodeManagedRuntimeProjectionSchema(
  value: unknown,
): ManagedRuntimeProjectionSchema {
  const root = record(value, "$");
  const snapshot = decodeManagedRuntimeSnapshot(root.snapshot);
  const changePage = decodeManagedRuntimeChangePage(root.change_page);
  if (snapshot.thread_id !== changePage.thread_id) {
    throw new ManagedRuntimeContractDecodeError(
      "$.change_page.thread_id",
      "snapshot thread_id",
    );
  }
  return { snapshot, change_page: changePage };
}

export function encodeManagedRuntimeProjectionSchema(
  value: ManagedRuntimeProjectionSchema,
): ManagedRuntimeProjectionSchemaWire {
  return {
    snapshot: encodeManagedRuntimeSnapshot(value.snapshot),
    change_page: encodeManagedRuntimeChangePage(value.change_page),
  };
}

